import{_ as r,o as e,c as a,a9 as o}from"./chunks/framework.D4xYp1Zt.js";const n="/images/from-1-to-1000000/1-dot2-150x111.png",p="/images/from-1-to-1000000/10-dots1.png",s="/images/from-1-to-1000000/Moon.png",l="/images/from-1-to-1000000/1-in-20.png",i="/images/from-1-to-1000000/gay-lesbian-bisexual.png",h="/images/from-1-to-1000000/princesses1.png",m="/images/from-1-to-1000000/100-dots1.png",g="/images/from-1-to-1000000/1100th1.png",c="/images/from-1-to-1000000/blind1.png",f="/images/from-1-to-1000000/apple.png",w="/images/from-1-to-1000000/flush.png",b="/images/from-1-to-1000000/millionaires.png",_="/images/from-1-to-1000000/1000-dots1.png",d="/images/from-1-to-1000000/neutron-star.png",u="/images/from-1-to-1000000/minutes-in-a-day.png",k="/images/from-1-to-1000000/perfect-SAT1.png",y="/images/from-1-to-1000000/exoplanets.png",x="/images/from-1-to-1000000/stars.png",v="/images/from-1-to-1000000/seconds-in-an-hour.png",S="/images/from-1-to-1000000/religions-in-the-world1.png",T="/images/from-1-to-1000000/languages.png",P="/images/from-1-to-1000000/sand1.png",A="/images/from-1-to-1000000/10000-dots.png",W="/images/from-1-to-1000000/Fenway.png",q="/images/from-1-to-1000000/manhattan-buildings.png",C="/images/from-1-to-1000000/Craigslist.png",F="/images/from-1-to-1000000/seconds-in-a-day.png",M="/images/from-1-to-1000000/100000-dots.png",B="/images/from-1-to-1000000/abortions1.png",j="/images/from-1-to-1000000/Million-Dots-one-red3.png",D="/images/from-1-to-1000000/million-poster_large.jpg",N="/images/from-1-to-1000000/million-1in10000_large.jpg",R="/images/from-1-to-1000000/million-1in100_large.jpg",U="/images/from-1-to-1000000/pinit_fg_en_rect_gray_20.png",K=JSON.parse('{"title":"From 1 to 1,000,000","description":"","frontmatter":{"title":"From 1 to 1,000,000","titleZh":"从1到100万","date":"2014-11-14T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/11/from-1-to-1000000.html","slug":"from-1-to-1000000"},"headers":[],"relativePath":"posts/from-1-to-1000000.md","filePath":"posts/from-1-to-1000000.md","lastUpdated":1782886257000}'),G={name:"posts/from-1-to-1000000.md"};function I($,t,H,L,O,V){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="从1到100万-·-from-1-to-1-000-000" tabindex="-1">从1到100万 · From 1 to 1,000,000 <a class="header-anchor" href="#从1到100万-·-from-1-to-1-000-000" aria-label="Permalink to &quot;从1到100万 · From 1 to 1,000,000&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/11/from-1-to-1000000.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/11/from-1-to-1000000.html</a> · 2014-11-14</p></blockquote><p>听着。我不知道你在那边想些什么。可能是简单的,也可能是复杂的;可能是平淡的,也可能是异想天开的;可能是实用的,也可能是让人毛骨悚然的。</p><p>但我在这边想的是数字。又是数字。</p><p>我从来没觉得词语有多了不起。它们黏糊糊的,有时讨人喜欢,有时讨人厌。它们微妙、主观、絮絮叨叨、随波逐流。词语嘛,还行吧。随便啦。</p><p>但数字。数字迷人、精确、令人满足、令人回味无穷,不管你此时此刻在想什么,至少有 60% 的概率我这边在想数字。</p><p>所以我决定不写一篇,而是连着写两篇关于数字的文章,期间我们将从 1 开始,最终抵达一个非常吓人的地方。今天,我们把话题限定在寻常和可以想象的范围内,上限定在一百万。</p><p>1 到 1,000,000 之间的数字在日常生活中随处可见。1、10、100、1,000、10,000 和 100,000 都是我们的老朋友——我们懂它们,它们懂我们,而在这篇文章里,我们基本上就是要和它们叙叙旧、聊聊近况,因为你大概一直没好好和它们保持联系。</p><p>咱们从头开始——</p><p><strong>一位数</strong></p><p>我们就从极其无聊的 1 说起。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/1-dot2.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="1 dot"></a></p><p>1 喜欢把自己伪装成一种诗意而深奥的东西,常被用在一些我根本听不懂的句子里,比如「万物之一」什么的,烦死人。可一旦你真的花时间跟 1 相处,最后都会觉得无聊透顶。</p><p>1 玩起来也没意思。用它做乘除法的体验乏善可陈,它简直是个哑炮,以至于——即便它只有一个因数——它居然还不算质数。</p><p>至于剩下的一位数,我喜欢 2、4、8,因为我七岁时痴迷于一口气念出「2、4、8、16、32、64、128、256、512、1,024、2,048、4,096」,然后就撞墙卡住了,<a href="#footnote-1-2931">1</a> 而且我天生就偏爱质数,所以 3、5、7 也在我心目中占有一席之地。对 9 不太来电,但至少它是个完全平方数。至于 6,它对我人生唯一的贡献就是每次我要告诉别人电话号码时把我烦得要死——(xxx)-666-xxxx——对方总免不了要有点反应,然后我们就得围绕这个来一段小小的对话表演。<a href="#footnote-2-2931">2</a></p><p>继续往下走。</p><p><strong>两位数</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/10-dots1.png" target="_blank" rel="noreferrer"><img src="'+p+'" alt="10 dots"></a></p><p>进入两位数之后,有意思的事情终于开始出现了。10 本身就是个大数,因为我们整套十进制的存在就源于它。为什么我们最终用的是十进制(而不是像八进制那样数成 1、2、3、4、5、6、7、10、11、12、13、14、15、16、17、20 等等)?因为我们有 10 根手指。看起来只有十进制才能让你在乘除以及以 10 的倍数移动小数点、加零的时候如此简单直观——但其实任何进制都是这样的。<a href="#footnote-3-2931">3</a> 我们来看看一些更大的数——</p><p>12 有「一打」这个身份,还有一堆因数。它也是<a href="http://www.universetoday.com/55512/how-many-people-have-walked-on-the-moon/" target="_blank" rel="noreferrer">登上过月球</a>的人数。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/Moon.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Moon"></a></p><p>让我们停一下,好好感慨一下——人类能把人类送上月球并且安全带回来,这件事有多<em>离谱</em>地了不起。而那 12 个人<em>有多幸运</em>?还有什么人生体验能比在月球上蹦跶、同时看着地球悬在太空里更令人向往?</p><p>继续往下,我不知道 13 睡了谁的姐姐,但反正它在某个环节得罪了不该得罪的人,最后成了唯一一个背着实打实臭名声的数字。</p><p>20 值得提一嘴,只是因为我在查资料时读到,美国大约每 <a href="https://www.census.gov/compendia/statab/2012/tables/12s0209.pdf" target="_blank" rel="noreferrer">20 个男人里只有 1 个</a>身高在 6 英尺 2 英寸 (1.88 米) 或以上。所以如果你身高 6&#39;2&quot; 以上,那你就是下面这组随机抽的 20 个美国男人里最高的那个——<a href="#footnote-4-2931">4</a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/1-in-20.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="1 in 20"></a></p><p>33 值得一提是因为拉里·伯德 (Larry Bird),也因为我周三就是这个岁数了,谢谢你们没有一个人祝我生日快乐。</p><p>你可能会惊讶地发现,美国只有 <a href="https://www.cdc.gov/nchs/data/nhsr/nhsr077.pdf" target="_blank" rel="noreferrer">1/43 的人公开认同自己是同性恋、女同性恋或双性恋</a>,但在<a href="http://www.nber.org/papers/w19508.pdf" target="_blank" rel="noreferrer">匿名且经过遮掩的问卷中</a>,这个数字跳到了 8/43:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/gay-lesbian-bisexual.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="gay lesbian bisexual"></a></p><p>迪士尼公主有 41 位,<a href="http://theknow.ask.com/how-many-real-princesses-are-there-in-the-world-today" target="_blank" rel="noreferrer">现实中的公主有 48 位</a>,其中没有一个是<a href="http://www.thedailybeast.com/articles/2013/08/05/kate-middleton-why-be-a-duchess-when-you-can-be-a-princess.html" target="_blank" rel="noreferrer">凯特·米德尔顿 (Kate Middleton)</a>。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/princesses1.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="princesses"></a></p><p>两位数里剩下的没啥好说的,直到我们碰上油腻的 99——那个靠着「站在 100 旁边」这份工作混了一辈子的价签婊。</p><p><strong>三位数</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/100-dots1.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="100 dots"></a></p><p>100 是个大人物,而且它心里清楚——不过这也公平。它是第一个三位数,但在我们的世界里,100 的主要角色是当一位数和两位数群体的霸主——它是一个世纪的年数,是官方认证的「行了你赢了」的年龄,而百分比这整个概念不过是拿 100 的一部分去比 100 的全部。100 还是另一个基本数(即 10、100、1,000 等等)的完全平方,这挺让人满足的。</p><p>在某方面处于一个群体的前百分之一也是件事。它看起来是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/1100th1.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="1:100th"></a></p><p>如果在财富上你是那个红点,你就是臭名昭著的 <em>1%</em>,会有一堆人举着对你不友好的标语。要在美国人里当红点,你得年赚<a href="http://www.nytimes.com/interactive/2012/01/15/business/one-percent-map.html?_r=0" target="_blank" rel="noreferrer">将近 40 万美元</a>,但在全世界范围内当红点只需要大约十分之一(2011 年是 <a href="http://www.forbes.com/sites/timworstall/2011/10/17/who-are-the-99/" target="_blank" rel="noreferrer">39,000 美元</a>)。</p><p>在 SAT 上,如果你考了 1600 里的 1480 或者 2400 里的 2200,<a href="http://www.collegeboard.com/prod_downloads/highered/ra/sat/SATPercentileRanksCompositeCR_M_W.pdf" target="_blank" rel="noreferrer">你就是那个红点</a>;而 ACT 上,<a href="http://www.actstudent.org/scores/norms1.html" target="_blank" rel="noreferrer">你需要 33 分</a>。<a href="http://www.iqcomparisonsite.com/iqtable.aspx" target="_blank" rel="noreferrer">斯坦福-比奈智商 (Stanford-Binet IQ)</a> 137 也会让你成为红点,这意味着 99% 的人都比你笨。<a href="#footnote-5-2931">5</a></p><p>过了 100,我们就要进入极度随机的数字领域了,但首先我们要碰到 101,这是个 C 级数字名人,靠着几个不大的名头——比如《101 忠狗》、入门课程 (101 课程) 以及美国西海岸公路——混了个脸熟。</p><p>继续往下,大约每 100 个点里就有 1 个会说手语(全球 <a href="https://research.gallaudet.edu/Demographics/deaf-US.php" target="_blank" rel="noreferrer">7000 万</a>人),<a href="#footnote-6-2931">6</a> 而每 179 个活着的人里就有 1 个(<a href="http://www.who.int/mediacentre/factsheets/fs282/en/" target="_blank" rel="noreferrer">3900 万</a>)是盲人:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/blind1.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="blind"></a></p><p>全世界有 444 家 <a href="http://store.apple.com/us/browse/open/country_selector" target="_blank" rel="noreferrer">Apple 零售店</a>:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/apple.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="apple"></a></p><p>如果你<a href="https://en.wikipedia.org/wiki/Poker_probability" target="_blank" rel="noreferrer">发五张牌</a> 508 次,平均会拿到一次同花:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/flush.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="flush"></a></p><p>而全世界有 1200 万个美元百万富翁,也就是每 583 个人里有 1 个。如果你的总资产(减去总负债之后)超过 100 万美元,你就是下图里的那个红点:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/millionaires.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt="millionaires"></a></p><p><strong>四位数</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/1000-dots1.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt="1,000 dots"></a></p><p>1,000 在我们的世界里也是个大人物,有一堆外号,比如 a grand、a G、a kilo、还有 k。它还是「数量级」这条精英数字链条里的成员之一 —— 我们熟悉的百万 (million)、十亿 (billion)、万亿 (trillion) 等等。其实百万是这条链里的第三个数,第一个是那个废柴 1,第二个是 1,000。而 1,000 正是定义整条链的关键乘数。</p><p>话虽如此,1,000 有个不可告人的秘密:它和 10 一样是个骗子,没法开成整齐的平方。1,000 的平方根是一个尴尬到不行的 31.62277660168 <em>等等等等</em>,连个循环节都没有。<a href="#footnote-7-2931">7</a></p><p>好了,来看看一些四位数和概率:</p><p>这是<a href="http://www.space.com/3482-star-shatters-spinning-speed-record.html" target="_blank" rel="noreferrer">一颗中子星每<em>秒</em>自转的次数</a>:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/neutron-star.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="neutron star"></a></p><p>这是一天有多少分钟:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/minutes-in-a-day.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="minutes in a day"></a></p><p>天才级的 150 智商能让你在千点智力图上拿到红点身份,但这并不意味着你能在 SAT 上拿满分 1600 —— 只有 1,489 点样本中的那个红点才能 SAT 满分:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/perfect-SAT1.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt="perfect SAT"></a></p><p>美国有 <a href="http://dmdatabases.com/databases/business-mailing-lists/how-many-businesses" target="_blank" rel="noreferrer">1,811 家大型企业</a>(员工超过 10,000 人),天文学家已经识别出 <a href="http://exoplanet.eu/catalog/" target="_blank" rel="noreferrer">1,849 颗太阳系外行星</a>:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/exoplanets.png" target="_blank" rel="noreferrer"><img src="'+y+'" alt="exoplanets"></a></p><p>在一个完美晴朗的夜晚,我们能在夜空中看到大约 2,500 颗星星:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/stars.png" target="_blank" rel="noreferrer"><img src="'+x+'" alt="stars"></a></p><p>现今活着的身高超过 7 英尺(213 厘米)的人可能<a href="http://www.naturalheightgrowth.com/2012/08/11/how-many-7-feet-tall-people-are-in-the-world/" target="_blank" rel="noreferrer">只有 2,800 位</a>,但他们每人有 <a href="http://www.theatlantic.com/business/archive/2012/05/how-much-should-we-tax-7-footers/256757/" target="_blank" rel="noreferrer">17% 的概率</a>进入 NBA。</p><p>这是一小时里所有的秒数:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/seconds-in-an-hour.png" target="_blank" rel="noreferrer"><img src="'+v+'" alt="seconds in an hour"></a></p><p>这是<a href="http://www.adherents.com/" target="_blank" rel="noreferrer">世界上宗教的数量</a>:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/religions-in-the-world1.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt="religions in the world"></a></p><p>所以世界上的宗教数量比我们夜空中能看到的星星还多,就算你每秒念一个宗教的名字,念完全部也得花一个多小时。</p><p>我们已经识别出全世界超过 <a href="https://archive.org/details/globalbiodiversi92wcmc" target="_blank" rel="noreferrer">40 万种甲虫</a>,但哺乳动物只有 <a href="http://www.departments.bucknell.edu/biology/resources/msw3/documents/MSW3Citations.pdf" target="_blank" rel="noreferrer">5,416 种</a>。</p><p>再看看世界上有多少种<a href="http://www.infoplease.com/askeds/many-spoken-languages.html" target="_blank" rel="noreferrer">现存语言</a>:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/languages.png" target="_blank" rel="noreferrer"><img src="'+T+'" alt="languages"></a></p><p>最后,一个 1 立方厘米的盒子里能装下多少颗中等大小(直径 0.5 毫米)的沙粒:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/sand1.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt="sand"></a></p><p><strong>五位数</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/10000-dots.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt="10,000 dots"></a></p><p>如果说 1,000 有点被高估,那 10,000 就是被低估了。没人聊 10,000,但不像开不出整数平方根的 1,000,10,000 是完美的平方数——100 个 100,而且是 100 万的 1%。</p><p>据说斯蒂芬·霍金 (Stephen Hawking) 的智商是 160,这刚好够他在一份 10,000 人的人类智力平均样本里当那颗红点。顺便告诉你,在一个 17,000 人的普通群体中,<a href="http://www.ncbi.nlm.nih.gov/pmc/articles/PMC2211462/%20" target="_blank" rel="noreferrer">会有一个白化病人</a>。</p><p>以下是<a href="http://boston.redsox.mlb.com/bos/ballpark/information/index.jsp?content=facts" target="_blank" rel="noreferrer">满座的芬威球场 (Fenway Park)</a> 能容纳的人数:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/Fenway.png" target="_blank" rel="noreferrer"><img src="'+W+'" alt="Fenway"></a></p><p>比芬威球场里的人数更多的,是全世界的 <a href="https://www.cia.gov/library/publications/the-world-factbook/fields/2053.html" target="_blank" rel="noreferrer">41,821 座机场</a>,以及<a href="http://www.nytimes.com/2013/12/22/nyregion/calculating-the-number-of-windows-on-buildings-in-manhattan.html?_r=0" target="_blank" rel="noreferrer">曼哈顿的建筑数量</a>:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/manhattan-buildings.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt="manhattan buildings"></a></p><p><a href="https://investor.google.com/financial/tables.html" target="_blank" rel="noreferrer">谷歌 (Google) 的 55,030 名员工</a>能装满一个大型体育场,<a href="https://www.apple.com/about/job-creation/" target="_blank" rel="noreferrer">苹果 (Apple) 的 50,250 人</a>也一样。Facebook <a href="http://newsroom.fb.com/company-info/" target="_blank" rel="noreferrer">规模就小得多了</a>,员工 8,348 人;而维基百科 (Wikipedia) 只用<a href="https://en.wikipedia.org/wiki/Wikimedia_Foundation" target="_blank" rel="noreferrer">区区 208 个人</a>在运营。至于 <a href="http://www.craigslist.org/about/factsheet" target="_blank" rel="noreferrer">Craigslist 团队</a>,塞进一辆小巴车就够了:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/Craigslist.png" target="_blank" rel="noreferrer"><img src="'+C+'" alt="Craigslist"></a></p><p>而每天滴答流逝的秒数是这么多:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/seconds-in-a-day.png" target="_blank" rel="noreferrer"><img src="'+F+'" alt="seconds in a day"></a></p><p><strong>六位数</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/100000-dots.png" target="_blank" rel="noreferrer"><img src="'+M+'" alt="100,000 dots"></a></p><p>10 万是这篇文章里最随机的一个主类别数字。在生活中,它主要以「大多数人都很想拿到手的年薪」这种形式出现。它也非常接近我实际能想象出「所有人聚在同一个地方」的最大人数。密歇根球场 (The Big House) 容量刚好不到 11 万,而世界上最大的体育场是印度的<a href="http://eastbengalfootballclub.com/stadium.php" target="_blank" rel="noreferrer">盐湖体育场 (Salt Lake Stadium)</a>,容量为 12 万。朝鲜声称他们的绫罗岛五一体育场能容纳 15 万人,但朝鲜还说过金正日第一次打高尔夫就<a href="http://www.cybergolf.com/golf_news/alltime_golf_scoring_record_goes_with_death_of_kim_jong_il" target="_blank" rel="noreferrer">打出了 11 个一杆进洞</a>,所以我们还是把盐湖体育场当作世界最大。<a href="#footnote-8-2931">8</a></p><p>和世界最大体育场容量相等的,是全球<a href="http://www.who.int/reproductivehealth/publications/unsafe_abortion/induced_abortion_2012.pdf" target="_blank" rel="noreferrer">平均每天</a>发生的堕胎数量:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/abortions1.png" target="_blank" rel="noreferrer"><img src="'+B+'" alt="abortions"></a></p><p>这大约是<a href="http://www.ecology.com/birth-death-rates/" target="_blank" rel="noreferrer">全球每日出生数</a>的三分之一,意味着在所有没有以流产告终的怀孕中,四分之一以堕胎收场。这跟<a href="https://www.cdc.gov/mmwr/preview/mmwrhtml/ss6208a1.htm?s_cid=ss6208a1_w" target="_blank" rel="noreferrer">美国的比例</a>差不多,但在纽约市,每 100 例非流产怀孕中就有 <a href="http://www.nyc.gov/html/doh/downloads/pdf/vs/2009sum.pdf" target="_blank" rel="noreferrer">41 例</a>以堕胎结束。不,这并不是要发表什么政治立场,只是一个有意思(而且对我来说很意外)的统计数据,大家冷静点。</p><p><strong>100 万</strong></p><p>祝你好运。底下见——</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/11/Million-Dots-one-red3.png" target="_blank" rel="noreferrer"><img src="'+j+'" alt="Million Dots"></a></p><p>抱歉。100 万个点真的是很多点。</p><p>那么百万分之一的概率有多小?百万分之一的机会有多渺茫?你就试着在上面这 100 万个点里找出那个红色的点吧。</p><p>这是我能想到的、唯一能可视化「100 万」或「百万分之一」实际意味着什么的方式。</p><p>100 万这个数字很有意思,因为它很大——但同时它又是「大数字」里最小的那个,<em>刚好</em>小到你还能想象出来、还能在图里画出来。它正好处在「我们大脑能理解的世界」和「彻底无法想象的世界」的边界上。</p><p>如果你找到了那个红点,下次买 1.46 亿分之一中奖率的强力球彩票时,或者听到诸如<a href="http://www.discovery.com/tv-shows/curiosity/topics/big-question-what-are-odds-of-surviving-plane-crash.htm" target="_blank" rel="noreferrer">每 1100 万次</a>飞机航班中有一次坠机之类的事实时,记住它是件好事。百万分之一的极小概率,相当于扔三个 100 面的骰子,试图<em>一次投掷就让三个骰子全都掷出 63</em>。</p><p>如果你想玩玩百万分之一的概率,挑一个 1 到 1,000,000 之间的数字,大声说出来,然后点击下面的 Generate 试试看能不能掷中它(或者另外两种玩法:1) 把最大值改成 1,000,试着用接下来两次点击掷中你说的数字;2) 把最大值改成 100,试着连续三次掷中同一个选定的数字):</p><p><br> 这个小工具生成的数字来自 RANDOM.ORG 的真随机数生成器。<br></p><p><strong>百万点海报</strong></p><p>我既喜欢 1,000,000 这个数字,也喜欢 1/1,000,000 这个数字,而且我热爱任何能把它们可视化的机会。一篇博客文章横向最多只能塞下 200 个点,这可不是可视化一百万的理想方式,因为它会形成一个 1 x 25 的矩形,你得往下滑一个小时才能看完全部。所以我们做了一张<a href="https://store.waitbutwhy.com/collections/posters/products/one-in-a-million-poster-24x24" target="_blank" rel="noreferrer">百万点海报</a>。</p><p>这张海报令人满意地是个正方形。24″ x 24″(61 厘米 x 61 厘米)的海报,由 1,000 点 x 1,000 点组成的正方形,总共一百万个点。这能让你最有效地可视化一百万这个数字(它也有助于可视化 5 百万、1 千万、1 亿甚至 10 亿——只要想象多张海报并排放在一起就行)。</p><p>当然,其中一个点是红色的。要找到它得费点功夫,<a href="#footnote-9-2931">9</a> 但一旦你找到了,你就能确切理解 1/1,000,000 意味着什么。所以一张海报,两个极端数字可视化。你可以在<a href="https://store.waitbutwhy.com/collections/posters/products/one-in-a-million-poster-24x24" target="_blank" rel="noreferrer">这里</a>看看。</p><p>普通版长这样:</p><p><strong>完整海报:</strong></p><p><a href="https://store.waitbutwhy.com/collections/posters/products/one-in-a-million-poster-24x24" target="_blank" rel="noreferrer"><img src="'+D+'" alt="million-posterlarge"></a></p><p><strong>近一点的镜头,展示中间的红点:</strong></p><p><a href="https://store.waitbutwhy.com/collections/posters/products/one-in-a-million-poster-24x24" target="_blank" rel="noreferrer"><img src="'+N+'" alt="Closer up"></a></p><p><strong>特写镜头,展示那个红点:</strong></p><p><a href="http://store.waitbutwhy.com/collections/posters" target="_blank" rel="noreferrer"><img src="'+R+'" alt="Up close"></a></p><h2 id="数字系列-2-从-1-000-000-到葛立恒数" tabindex="-1"><strong>数字系列 #2:</strong> <a href="https://waitbutwhy.com/2014/11/1000000-grahams-number.html" target="_blank" rel="noreferrer">从 1,000,000 到葛立恒数</a> <a class="header-anchor" href="#数字系列-2-从-1-000-000-到葛立恒数" aria-label="Permalink to &quot;**数字系列 #2:** [从 1,000,000 到葛立恒数](https://waitbutwhy.com/2014/11/1000000-grahams-number.html)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请注册我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><h2 id="想支持-wait-but-why-请访问我们的-patreon-页面。" tabindex="-1">想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。 <a class="header-anchor" href="#想支持-wait-but-why-请访问我们的-patreon-页面。" aria-label="Permalink to &quot;想支持 Wait But Why,请访问我们的 **[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p><strong>相关 Wait But Why 文章</strong></p><p><a href="https://waitbutwhy.com/2013/08/putting-time-in-perspective.html" target="_blank" rel="noreferrer">把时间放进透视图里</a><br><a href="https://waitbutwhy.com/2014/03/combined-wealth-world.html" target="_blank" rel="noreferrer">241 万亿美元能买些什么?</a><br><a href="https://waitbutwhy.com/2013/10/what-does-quadrillion-sour-patch-kids.html" target="_blank" rel="noreferrer">一千万亿颗酸味小孩糖 (Sour Patch Kids) 长什么样?</a></p><hr><ol><li><p>别的小孩都在外面玩。<a href="#note-1-2931">↩</a></p></li><li><p>至少某天我会有个新的电话号码——哦等等,你第一个智能手机的号码从此就是你永远的号码了。<a href="#note-2-2931">↩</a></p></li><li><p>其他进制也被用过,比如<a href="http://www-history.mcs.st-and.ac.uk/HistTopics/Mayan_mathematics.html" target="_blank" rel="noreferrer">玛雅人当年用的</a>是 20 进制。<a href="#note-3-2931">↩</a></p></li><li><p>是的,把这个事实扯进来有点随机——习惯一下吧,因为这整篇文章就是我在朝你脸上乱扔东西。<a href="#note-4-2931">↩</a></p></li><li><p>智商 (IQ) 算是个伪概念,但用一个数字来量化每个人的智力还是挺好玩的。<a href="#note-5-2931">↩</a></p></li><li><p>我不确定这些人里有多少是聋人,但美国有 60 万功能性聋人,也就是每 454 人里有 1 个。<a href="#note-6-2931">↩</a></p></li><li><p>WordPress 的拼写检查在 vinculum 下面划了红线,虽然它是个真词——因为 WordPress 已经被我这篇文章的走向惊呆了。<a href="#note-7-2931">↩</a></p></li><li><p>我也去过朝鲜那个体育场(我在那儿拍了<a href="https://www.youtube.com/watch?v=UPThbdSFg8M" target="_blank" rel="noreferrer">这段视频</a>),看起来跟一个普通 NFL 体育场差不多大。这条注释我本来是放在上面那句话里的,但作为正文内容感觉有那么一点点太炫耀了。<a href="#note-8-2931">↩</a></p></li><li><p>谁能搞清楚那个点为什么在网格里的那个位置,加分。<a href="#note-9-2931">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/11/from-1-to-1000000.html&amp;description=From%201%20to%201,000,000" target="_blank" rel="noreferrer"><img src="'+U+'" alt=""></a></p>',121)])])}const Q=r(G,[["render",I]]);export{K as __pageData,Q as default};
